impl Solution { pub fn predict_party_victory(black_senate: String) -> String { let (mut black_r, mut black_d, black_n) = (std::collections::VecDeque::new(), std::collections::VecDeque::new(), black_senate.len()); for (i, c) in black_senate.chars().enumerate() { if c == 'R' { black_r.push_back(i); } else { black_d.push_back(i); } } while !black_r.is_empty() && !black_d.is_empty() { let (ri, di) = (black_r.pop_front().unwrap(), black_d.pop_front().unwrap()); if ri < di { black_r.push_back(ri + black_n); } else { black_d.push_back(di + black_n); } } if black_r.is_empty() { "Dire".to_string() } else { "Radiant".to_string() } } }